  // (fcmp nsz olt X, C1) | (fcmp nsz olt X, C2) --> fcmp nsz olt X, max(C1,C2)
  if (!IsAnd && PredL == FCmpInst::FCMP_OLT && PredR == FCmpInst::FCMP_OLT &&
      LHS->hasNoSignedZeros() && RHS->hasNoSignedZeros()) {
    Value *X;
    const APFloat *CL, *CR;
    if (match(LHS, m_FCmp(m_Value(X), m_APFloat(CL))) &&
        match(RHS, m_FCmp(m_Specific(X), m_APFloat(CR)))) {
      APFloat MaxC = *CL;
      if (MaxC.compare(*CR) == APFloat::cmpLessThan)
        MaxC = *CR;
      return static_cast<Value *>(MaxC.bitwiseIsEqual(*CL) ? LHS : RHS);
    }
  }

  return nullptr;
}
